/**
 * data.js — Bodhanika experiment library
 * Structure: { id, title, subject, classes[], icon, bgGrad, desc, ncert,
 *              why, materials[], steps[], simId, buddy }
 */
window.EXPERIMENTS_1_5 = [

/* ══════════════ CLASS 1 ══════════════ */
{id:'c1-s1',title:'Sink or Float?',subject:'Science',classes:['1'],icon:'🛁',bgGrad:'rgba(255,107,107,.18)',desc:'Drop objects in water and predict whether they sink or float. Discover density basics.',ncert:'NCERT EVS Class 1 – Things Around Us',why:'Objects float when less dense than water. A leaf floats because it traps air; a stone sinks because it is denser. This is the principle of buoyancy.',materials:['A bowl of water','Leaf, coin, cork, stone, sponge, pencil'],steps:['Fill a bowl with water.','Pick up each object and guess: sink or float?','Gently place it on the water surface.','Record your results.','Did anything surprise you?'],simId:'sink-float',buddy:"Even big ships float because they are hollow — they displace a huge amount of water! This is called Archimedes' Principle."},
{id:'c1-s2',title:'Shadow Play',subject:'Science',classes:['1'],icon:'🕯️',bgGrad:'rgba(255,107,107,.18)',desc:'Use a torch to make shadows. Learn how light travels in straight lines.',ncert:'NCERT EVS Class 1 – Ch 3: Light and Shadows (Looking Around)',why:'Light travels in straight lines. When an object blocks light, a shadow forms on the other side. The closer the object to the light, the bigger the shadow.',materials:['A torch','Your hand or a cardboard shape','A white wall or sheet'],steps:['Darken the room.','Shine the torch at the wall.','Place your hand between the torch and wall.','Move your hand closer — shadow grows!','Make animal shapes with your fingers.'],simId:'shadow-play',buddy:'Shadows are always on the opposite side from the light source. On a sunny day, your shadow points away from the sun!'},
{id:'c1-s3',title:'Colour Mixing',subject:'Science',classes:['1'],icon:'🎨',bgGrad:'rgba(255,107,107,.18)',desc:'Mix primary colours to see what new colours you can make!',ncert:'NCERT EVS Class 1 – Colours Around Us',why:'Red, Blue, and Yellow are primary colours. Mix two to get a secondary colour: Red+Blue=Purple, Blue+Yellow=Green, Red+Yellow=Orange.',materials:['Food colouring or paint (red, blue, yellow)','3 clear glasses of water','Spoon'],steps:['Fill 3 glasses with water.','Add red to glass 1, blue to glass 2, yellow to glass 3.','Mix red + blue. What colour?','Mix blue + yellow. What colour?','Mix red + yellow. What colour?'],simId:'colour-mixing',buddy:'Light mixes differently from paint! Mixing all light colours gives white. Mixing all paint colours gives muddy brown. Cool, right?'},
{id:'c1-s4',title:'Parts of a Plant',subject:'Science',classes:['1'],icon:'🌻',bgGrad:'rgba(255,107,107,.18)',desc:'Label and learn the parts of a plant and what each part does.',ncert:'NCERT EVS Class 1 – Plants Around Us',why:'Each part has a job: roots absorb water, stem carries water up, leaves make food using sunlight, flowers attract pollinators, seeds make new plants.',materials:['A small potted plant','Paper and pencil'],steps:['Look at the plant carefully.','Draw it on paper.','Label: roots, stem, leaves, flower (if any).','Gently touch the stem — feel how firm it is?','Water the soil and watch where the water goes.'],simId:'plant-parts',buddy:"A plant is like a tiny food factory! It takes in sunlight, water and air — and makes its own food. That process is called photosynthesis."},
{id:'c1-s5',title:'Sense Detectives',subject:'Science',classes:['1'],icon:'👃',bgGrad:'rgba(255,107,107,.18)',desc:'Explore your 5 senses with fun tests. Which sense is the sharpest?',ncert:'NCERT EVS Class 1 – Our Senses',why:'We have 5 senses: sight (eyes), hearing (ears), smell (nose), taste (tongue), touch (skin). Each has special receptor cells sending signals to the brain.',materials:['Blindfold (cloth)','Objects with different textures','Items with different smells (lemon, soap, flower)'],steps:['Blindfold yourself.','A friend places an object in your hand — guess it by touch.','Smell a few things — can you name them?','Listen to sounds — guess what made them.','Taste sweet, sour, salty — which do you prefer?'],simId:'five-senses',buddy:'Your nose can smell over 1 trillion different smells! But you can only taste 5 things: sweet, salty, sour, bitter and umami.'},

{id:'c1-m1',title:'Counting with Objects',subject:'Maths',classes:['1'],icon:'🔢',bgGrad:'rgba(255,217,61,.18)',desc:'Use everyday objects to count from 1 to 20. Build number sense.',ncert:'NCERT Maths Class 1 – Numbers 1 to 20',why:'Counting objects builds real number sense. Each number represents an exact quantity — this is called one-to-one correspondence.',materials:['20 small objects (coins, seeds, buttons)','Paper and pencil'],steps:['Put 5 objects in a row.','Touch each one as you count: 1, 2, 3, 4, 5.','Add 5 more and count again.','Try counting backwards from 10!','Group into sets of 2 — how many pairs?'],simId:'count-objects',buddy:"Counting in groups (2s, 5s, 10s) is faster! That's why we have 10 fingers — our whole number system is built on groups of 10."},
{id:'c1-m2',title:'Shapes Hunt',subject:'Maths',classes:['1'],icon:'🔷',bgGrad:'rgba(255,217,61,.18)',desc:'Find circles, squares, triangles, and rectangles hiding in everyday objects.',ncert:'NCERT Maths Class 1 – Basic Shapes',why:'Circles have no corners, triangles have 3, squares have 4 equal sides, rectangles have 4 sides with 2 pairs equal.',materials:['Paper and pencil','Walk around your home'],steps:['Draw 4 columns: Circle, Square, Triangle, Rectangle.','Walk around your home.','List every object matching each shape.','Which shape did you find most?','Draw your favourite finding.'],simId:'shapes-hunt',buddy:'A wheel is a circle. A door is a rectangle. A sandwich slice is a triangle! Shapes are everywhere once you start looking.'},
{id:'c1-m3',title:'Taller or Shorter?',subject:'Maths',classes:['1'],icon:'📏',bgGrad:'rgba(255,217,61,.18)',desc:"Compare heights and lengths without a ruler using hands and feet.",ncert:'NCERT Maths Class 1 – Measurement',why:'Before standard units, people used body parts to measure. A "foot" was literally the length of a king\'s foot! Standard units make measurement fair for everyone.',materials:['A string or strip of paper','Pencil'],steps:['Measure your hand span (thumb to pinky, fully spread).','Measure your desk in hand spans.','Measure your height in "feet" (heel to toe steps).','Compare with a friend — same number?','Why might results differ?'],simId:'measurement-compare',buddy:'Ancient Egyptians used the "cubit" — the distance from elbow to fingertip. Different people got different measurements for the same object!'},
{id:'c1-m4',title:'More or Less?',subject:'Maths',classes:['1'],icon:'⚖️',bgGrad:'rgba(255,217,61,.18)',desc:'Compare groups of objects. Learn greater than and less than the fun way.',ncert:'NCERT Maths Class 1 – Comparison',why:'The symbols > and < are like a hungry mouth — it always opens toward the bigger number!',materials:['Two sets of small objects (e.g. 7 coins and 4 buttons)'],steps:['Place 7 coins in one row, 4 buttons in another.','Match them one-to-one.','Which row has leftover items?','That row has MORE.','Draw the < > mouth between the two numbers.'],simId:'more-less',buddy:'Think of > and < as a hungry crocodile mouth! It always opens toward the bigger number because it wants to eat MORE food. 🐊'},
{id:'c1-m5',title:'Pattern Maker',subject:'Maths',classes:['1'],icon:'🔴',bgGrad:'rgba(255,217,61,.18)',desc:'Create colour and shape patterns, then extend them. Spot the rule!',ncert:'NCERT Maths Class 1 – Patterns',why:'Patterns are the language of maths. Recognising a repeating rule (AB, ABB, ABC) is early algebra thinking.',materials:['Coloured blocks, beads, or draw shapes','Paper'],steps:['Make a pattern: Red, Blue, Red, Blue…','Ask: what comes next?','Try: Circle, Circle, Triangle…','Make your own pattern and let someone else continue it!','Try a growing pattern: 1, 2, 3, 4…'],simId:'pattern-maker',buddy:'Patterns are everywhere! Music has rhythm patterns, nature has petal patterns, days of the week repeat. Maths is the science of patterns!'},

{id:'c1-e1',title:'My Family Tree',subject:'EVS',classes:['1'],icon:'👨‍👩‍👧‍👦',bgGrad:'rgba(107,203,119,.18)',desc:'Draw your family tree and learn about family relationships.',ncert:'NCERT EVS Class 1 – My Family',why:'A family tree is a diagram showing family relationships across generations. It helps us understand who is related to whom.',materials:['Large paper','Pencil and colours','Family photos (optional)'],steps:['Draw yourself at the bottom centre.','Draw your parents above you, connected by lines.','Add your grandparents above them.','Add siblings beside you.','Add aunts, uncles, cousins on the sides.'],simId:'family-tree',buddy:'Every person on Earth is related to every other person — just go back far enough! We all share common ancestors from thousands of years ago.'},
{id:'c1-e2',title:'Weather Diary',subject:'EVS',classes:['1'],icon:'🌤️',bgGrad:'rgba(107,203,119,.18)',desc:'Observe and record the weather every day for a week. Spot patterns!',ncert:'NCERT EVS Class 1 – Weather Around Us',why:'Weather changes daily based on sun, wind, and moisture in the air. Recording observations builds scientific habits.',materials:['Notebook','Pencil','Simple symbols for sunny, cloudy, rainy, windy'],steps:['Every morning, look outside for 1 minute.','Draw a symbol: sun, cloud, rain, or wind.','Note if it\'s hot or cold.','After 7 days, count each type.','Which weather happened most this week?'],simId:'weather-diary',buddy:"Weather forecasters use thousands of data points to predict rain. But even they're wrong sometimes — weather is beautifully unpredictable!"},
{id:'c1-e3',title:'Living or Non-Living Sort',subject:'EVS',classes:['1'],icon:'🌱',bgGrad:'rgba(107,203,119,.18)',desc:'Sort objects into living and non-living groups. Build classification skills.',ncert:'NCERT EVS Class 1 – Living and Non-Living',why:'Living things grow, breathe, eat, reproduce and respond to their surroundings. Non-living things do not.',materials:['Pictures from magazines or draw your own','Two labelled sheets: Living / Non-Living'],steps:['Cut or draw 10 objects.','For each ask: Does it grow? Does it breathe?','Sort into Living or Non-Living.','Check tricky ones: fire? cloud? seed?','Share your reasoning!'],simId:'living-sort',buddy:'A seed looks non-living but is alive! A fire moves and "eats" fuel but is not alive. The key test: can it reproduce on its own?'},
{id:'c1-e4',title:'Clean Water Filter',subject:'EVS',classes:['1'],icon:'💧',bgGrad:'rgba(107,203,119,.18)',desc:'Make a simple filter using sand and gravel to clean muddy water.',ncert:'NCERT EVS Class 1 – Water Around Us',why:'Water filters work by physically trapping dirt particles. Larger gravel catches big debris, sand catches smaller particles — same idea as real water treatment plants.',materials:['Muddy water','Plastic bottle cut in half','Gravel, sand, cotton wool'],steps:['Place cotton wool at the bottom of the bottle neck.','Add a layer of gravel (2 cm).','Add a layer of sand (2 cm).','Pour muddy water through slowly.','Compare the water before and after — cleaner?'],simId:'water-filter',buddy:'Your filter removes dirt but not bacteria or chemicals! Real drinking water needs chemicals like chlorine and UV light treatment too.'},
{id:'c1-e5',title:'Soil Types Explorer',subject:'EVS',classes:['1'],icon:'🌍',bgGrad:'rgba(107,203,119,.18)',desc:'Collect different soils and compare their colour, texture, and ability to hold water.',ncert:'NCERT EVS Class 1 – Soil Around Us',why:'3 main soil types: sandy (drains fast), clay (holds water), loam (mix of both — best for plants). The type determines what can grow.',materials:['3 soil samples from different spots','3 clear jars','Water'],steps:['Collect soil from 3 spots (garden, path, field).','Feel each — is it gritty, smooth, or sticky?','Add water to each jar with soil. Shake.','Wait 10 minutes. Which looks clearest?','Which do you think is best for plants?'],simId:'soil-types',buddy:'It takes 1,000 years to form just 1 cm of good topsoil! Earthworms are nature\'s soil engineers — one worm can process 4 kg of soil per year.'},

{id:'c1-l1',title:'My Daily Routine',subject:'Life Skills',classes:['1'],icon:'⏰',bgGrad:'rgba(77,150,255,.18)',desc:'Build and understand a daily routine. Learn why order and time matter.',ncert:'Life Skills – CBSE Class 1',why:'Routines reduce decision fatigue and build self-discipline. When you do things in order every day, your brain automates them — freeing mental energy for learning.',materials:['Paper','Pencil and colours','Clock or watch'],steps:['Write or draw everything you do from wake-up to sleep.','Put them in time order.','Mark which activities you choose vs. must do.','Colour code: morning=yellow, afternoon=orange, night=blue.','Is there time for play AND study?'],simId:'daily-routine',buddy:'Top athletes and scientists all have strict routines. A consistent sleep time alone can improve your memory and focus at school!'},
{id:'c1-l2',title:'Saying Sorry Right',subject:'Life Skills',classes:['1'],icon:'🤝',bgGrad:'rgba(77,150,255,.18)',desc:"Role-play different scenarios. Learn what makes an apology genuine.",ncert:'Life Skills – CBSE: Empathy & Relationships',why:'A genuine apology has 3 parts: (1) Acknowledge what you did, (2) Say sorry sincerely, (3) Say what you\'ll do differently.',materials:['Just yourself and a partner or family member'],steps:['Think of a time you hurt someone\'s feelings.','Practise: "I know I did ___. I\'m sorry. Next time I\'ll ___."','Role-play: one person is upset, other apologises.','Switch roles.','How did a real sorry feel different from a forced one?'],simId:'apology-sim',buddy:'Saying sorry takes courage! It shows you care more about the other person than about being right.'},
{id:'c1-l3',title:'Hygiene Habits Check',subject:'Life Skills',classes:['1'],icon:'🧼',bgGrad:'rgba(77,150,255,.18)',desc:'Learn why and how to wash hands properly. Build lifelong hygiene habits.',ncert:'Life Skills – CBSE: Health & Hygiene',why:'Proper handwashing removes 99% of harmful bacteria and viruses. Rubbing for 20 seconds physically scrubs them away.',materials:['Soap','Water','Towel'],steps:['Wet your hands with clean water.','Apply soap.','Rub palms together.','Scrub between fingers and under nails.','Rinse well. Dry. Time it: 20 seconds — hum "Happy Birthday" twice!'],simId:'hand-wash',buddy:'Before handwashing was discovered, hospitals were deadly! Dr. Semmelweis proved in 1847 that doctors washing hands saved lives.'},
{id:'c1-l4',title:'Stranger Safety Scenarios',subject:'Life Skills',classes:['1'],icon:'🛡️',bgGrad:'rgba(77,150,255,.18)',desc:'Role-play safe responses to strangers. Know your trusted adults.',ncert:'Life Skills – CBSE: Personal Safety',why:'Children need clear, rehearsed responses to tricky situations. Knowing exactly what to say in advance means you won\'t freeze.',materials:['Just yourself and a trusted adult to role-play with'],steps:['Name 5 trusted adults in your life.','Role-play: stranger offers candy — what do you say?','Practise: "No thank you. I need to ask my parent."','Learn your home address and a parent\'s phone number.','Discuss: what places are safe to go if lost?'],simId:'safety-sim',buddy:'Your instincts are powerful! If something feels wrong, it probably is. You always have the right to say NO to any adult who makes you uncomfortable.'},
{id:'c1-l5',title:'My Feelings Wheel',subject:'Life Skills',classes:['1'],icon:'😊',bgGrad:'rgba(77,150,255,.18)',desc:'Identify and name your emotions. Learn that all feelings are valid.',ncert:'Life Skills – CBSE: Emotional Intelligence',why:'Naming an emotion activates the thinking part of the brain and reduces its intensity. Scientists call this "name it to tame it."',materials:['Paper (draw a large circle)','Colours','Pencil'],steps:['Divide your circle into 6 sections.','Draw one face in each: happy, sad, angry, scared, surprised, confused.','Colour each with a different colour.','Think of a time you felt each emotion.','Share one story with a family member.'],simId:'feelings-wheel',buddy:"Emotions aren't good or bad — they're information! Anger tells you something feels unfair. Fear tells you something feels dangerous. Listen to them."},

/* ══════════════ CLASS 2 ══════════════ */,
{id:'c2-s2',title:'Air Takes Up Space',subject:'Science',classes:['4','5','6'],icon:'💨',bgGrad:'rgba(255,107,107,.18)',desc:'Prove that air is real even though you cannot see it.',ncert:'NCERT Science Class 2 – Air Around Us',why:'Air is matter — it has mass and takes up space. Even though invisible, you can feel it push back when compressed.',materials:['Empty plastic bottle','Bowl of water','Balloon'],steps:['Squeeze an empty bottle — feel the air push back.','Submerge the "empty" bottle in water and open it — bubbles!','Blow up a balloon — you\'re filling it with air.','Let it go — air rushes out and propels the balloon.','Push a sealed bottle underwater — hard to push down, right?'],simId:'air-space',buddy:'A "flat" tyre still has air — just not enough. Racing cars use nitrogen instead of air in their tyres because nitrogen doesn\'t expand as much when hot!'},
{id:'c2-s3',title:'Ice to Water to Steam',subject:'Science',classes:['3','4'],icon:'🌡️',bgGrad:'rgba(255,107,107,.18)',desc:'Watch water change states. Solid → Liquid → Gas.',ncert:'NCERT Science Class 2 – States of Matter',why:'Heat makes molecules move faster — solid (slow), liquid (medium), gas (fast and spread out). Water is the only common substance we see in all 3 states naturally.',materials:['Ice cubes','A pot (with adult help)','A glass'],steps:['Hold an ice cube — feel it melt (solid→liquid).','Put water in a pot. Heat with adult help.','Observe steam rising — water turning to gas!','Hold a cold plate above the steam — droplets form (gas→liquid).','That\'s condensation — same as morning dew!'],simId:'states-matter',buddy:'Your breath on a cold day looks like steam — water vapour in your breath condenses when it meets cold air. You\'re making mini clouds!'},
{id:'c2-s4',title:'Seed Germination Race',subject:'Science',classes:['2'],icon:'🌱',bgGrad:'rgba(255,107,107,.18)',desc:'Grow seeds under different conditions. Which sprouts first?',ncert:'NCERT Science Class 2 – Plants Grow',why:'Seeds need water, warmth, and oxygen to germinate. They don\'t need sunlight at first — the seed contains stored food for the sprout.',materials:['4 bean or mung seeds','4 damp cotton balls','4 zip-lock bags','Labels'],steps:['Set up 4 bags with damp cotton and one seed each.','Label: Normal / No Water / Dark / Cold.','Place in different conditions.','Check daily for 7 days.','Which germinated first? Which didn\'t germinate?'],simId:'germination',buddy:'Seeds can survive for thousands of years! Scientists sprouted a 2000-year-old date palm seed found in a desert cave. It grew into a tree!'},

{id:'c2-m1',title:'Addition with Objects',subject:'Maths',classes:['2'],icon:'➕',bgGrad:'rgba(255,217,61,.18)',desc:'Use physical objects to understand addition as combining groups.',ncert:'NCERT Maths Class 2 – Addition up to 50',why:'Addition is combining two or more quantities. Using objects before numbers builds a concrete mental model.',materials:['20 small objects (coins, stones, beads)'],steps:['Put 7 objects in one pile, 5 in another.','Combine them and count.','Write: 7 + 5 = ?','Try different combinations up to 20.','Make a "number bond": draw two circles joined to one.'],simId:'addition-objects',buddy:"Your brain is doing addition constantly — counting steps on stairs, dividing snacks, splitting time. Maths is survival skill!"},
{id:'c2-m2',title:'Subtraction with Takeaway',subject:'Maths',classes:['2'],icon:'➖',bgGrad:'rgba(255,217,61,.18)',desc:'Use objects to show subtraction as taking away from a group.',ncert:'NCERT Maths Class 2 – Subtraction',why:'Subtraction is the inverse of addition — they undo each other. If 4+3=7, then 7−3=4.',materials:['15 small objects'],steps:['Start with 12 objects.','Take away 4. Count what\'s left.','Write: 12 − 4 = ?','Now add back the 4: what do you get?','Try: start with 15, take away 7, add 3 — what\'s left?'],simId:'subtraction-objects',buddy:'Shop assistants use subtraction to give change! If something costs ₹7 and you pay ₹10: 10−7=3. You get ₹3 back.'},
{id:'c2-m3',title:'Clock Reading Basics',subject:'Maths',classes:['2'],icon:'🕐',bgGrad:'rgba(255,217,61,.18)',desc:"Read o'clock and half-past times on an analogue clock.",ncert:'NCERT Maths Class 2 – Time',why:"An analogue clock face is divided into 12 hours and 60 minutes. The short hand points to the hour, the long hand counts minutes. Half past = 30 minutes past the hour.",materials:['A paper plate','Two strips of cardboard (clock hands)','A brass fastener'],steps:['Draw numbers 1–12 on the plate like a clock.','Attach hands with the fastener.','Set to 3 o\'clock — short hand on 3, long on 12.','Set to half past 6 — long hand on 6.','Quiz each other on different times.'],simId:'clock-reading',buddy:'Before clocks, people used sundials and water clocks! The first mechanical clock was invented around 1300 AD.'},
{id:'c2-m4',title:'Multiplication as Repeated Addition',subject:'Maths',classes:['2'],icon:'✖️',bgGrad:'rgba(255,217,61,.18)',desc:'Build multiplication from adding equal groups. See the connection!',ncert:'NCERT Maths Class 2 – Introduction to Multiplication',why:'3×4 means "3 groups of 4" which is the same as 4+4+4. Understanding this connection makes times tables meaningful.',materials:['20 small objects','Paper'],steps:['Make 3 groups of 4 objects each.','Count total objects.','Write: 4+4+4 = 12, and 3×4 = 12.','Make 5 groups of 2. Count and write.','Create a picture: 4 rows of 5 dots = 20.'],simId:'multiplication-intro',buddy:'A multiplication table is just shortcuts! 6×7=42 is faster than writing 7+7+7+7+7+7. The more you use it, the faster your brain recalls it.'},
{id:'c2-m5',title:'Money Maths',subject:'Maths',classes:['2'],icon:'💰',bgGrad:'rgba(255,217,61,.18)',desc:'Count coins and notes. Make the exact amount for a pretend purchase.',ncert:'NCERT Maths Class 2 – Money',why:'Money uses a base-10 system. 100 paise = ₹1. Understanding coin values and making change teaches place value in a real-world context.',materials:['Actual coins or draw them: ₹1, ₹2, ₹5, ₹10','Paper items with price tags'],steps:['Lay out coins: ₹1×3, ₹2×2, ₹5×1 — total?','Set up a "shop" with items priced ₹3, ₹7, ₹12.','Buy something. Count out the exact coins.','Can you make ₹10 in 3 different ways?','Give change from ₹20 for something costing ₹13.'],simId:'money-maths',buddy:'Every country has its own money system! India has Rupees, USA has Dollars, Europe has Euros. They all use the same maths though.'},

{id:'c2-e1',title:'Water Journey',subject:'EVS',classes:['2'],icon:'💧',bgGrad:'rgba(107,203,119,.18)',desc:'Trace where your tap water comes from and where it goes after the drain.',ncert:'NCERT EVS Class 2 – Water',why:'Tap water is sourced from rivers or groundwater, treated at a water plant, piped to homes, and after use goes to sewage treatment.',materials:['Paper and pencil'],steps:['Draw a house in the centre of your paper.','Draw: rain cloud → river → water treatment plant → your tap → drain → sewage plant → river again.','Ask: where does water come from in your city?','Turn off the tap while brushing — save 6 litres each time!','Calculate how much water your family uses in a day.'],simId:'water-journey',buddy:'Only 3% of Earth\'s water is fresh water — and most of that is frozen in glaciers! The water in your glass might once have been a cloud, a river, or a dinosaur!'},
{id:'c2-e2',title:'Food Groups Plate',subject:'EVS',classes:['2'],icon:'🍽️',bgGrad:'rgba(107,203,119,.18)',desc:'Build a balanced meal using the 5 food groups. Learn what each does for your body.',ncert:'NCERT EVS Class 2 – Food and Nutrition',why:'Our body needs different nutrients: carbohydrates for energy, protein to build muscles, fats for brain health, vitamins and minerals for immunity.',materials:['Paper plate','Pencil and colours or food pictures from magazines'],steps:['Divide your plate: half = vegetables & fruits; quarter = grains; quarter = protein.','Draw or paste foods in each section.','List what each food group does for your body.','Write your ideal breakfast using all 5 groups.','Check: did you have all 5 groups today?'],simId:'food-plate',buddy:'Your gut has more bacteria than there are stars in the Milky Way — and most of them are helpful! They help digest food and protect against illness.'},
{id:'c2-e3',title:'Transport Then and Now',subject:'EVS',classes:['2'],icon:'🚂',bgGrad:'rgba(107,203,119,.18)',desc:'Compare how people travelled 200 years ago vs. today. Spot the changes!',ncert:'NCERT EVS Class 2 – Transport',why:'Transport has evolved from walking and animals, to steam trains, to cars and aeroplanes. Each change was driven by the need for speed, safety, and convenience.',materials:['Paper divided into two columns: Then / Now'],steps:['List 5 ways people travel today.','For each, find what was used before it was invented.','Draw pairs: bullock cart → car, ship → aeroplane.','Which old method is still used in Kerala today?','What transport might exist in 50 years?'],simId:'transport-compare',buddy:'The first car could only go 16 km/h — slower than a bicycle! Today, a Shinkansen bullet train in Japan travels at 320 km/h.'},
{id:'c2-e4',title:'Animal Homes Match',subject:'EVS',classes:['2'],icon:'🦁',bgGrad:'rgba(107,203,119,.18)',desc:'Match animals to their homes and understand why each animal lives where it does.',ncert:'NCERT EVS Class 2 – Animals and Their Homes',why:'Animals live in habitats that meet their needs for food, water, shelter and safety. Their bodies are adapted to their habitat.',materials:['Paper','Pencil'],steps:['List 10 animals: lion, fish, bird, rabbit, bee, bear, ant, frog, eagle, dog.','Write their home next to each: den, burrow, nest, hive, water, tree, etc.','Draw 3 animals in their habitat.','Ask: why can\'t a fish live in a desert?','Find one animal that lives near your home.'],simId:'animal-homes',buddy:'Some animals share homes with other species! Clownfish live inside sea anemones for protection. The anemone gets food scraps in return. That\'s called symbiosis!'},
{id:'c2-e5',title:'Push and Pull Forces',subject:'EVS',classes:['5','6'],icon:'🚪',bgGrad:'rgba(107,203,119,.18)',desc:'Find all the push and pull forces in daily life. Understand force as a cause of movement.',ncert:'NCERT EVS Class 2 – Forces Around Us',why:'A force is a push or pull that can change an object\'s speed, direction, or shape. Everything that moves has a force acting on it.',materials:['Various objects at home'],steps:['Push a door open — that\'s a push force.','Pull open a drawer — that\'s a pull.','List 10 push actions and 10 pull actions from daily life.','Roll a ball and stop it — what did you do?','What forces act on a swing?'],simId:'push-pull',buddy:'Gravity is a pulling force from the Earth. It pulls everything toward the centre. That\'s why things fall down and why we stay on the ground.'},

{id:'c2-l1',title:'Sharing and Taking Turns',subject:'Life Skills',classes:['2'],icon:'🎲',bgGrad:'rgba(77,150,255,.18)',desc:'Play games that require taking turns. Learn why waiting is important.',ncert:'Life Skills – CBSE: Social Skills',why:'Taking turns builds patience, fairness, and trust. It\'s the foundation of democracy, sports, and cooperative work.',materials:['Any board game or card game','2 or more players'],steps:['Play a simple game: Snakes & Ladders, or cards.','Strict rule: no skipping turns.','If someone takes too long, politely say "your turn" — don\'t grab.','After the game: how did waiting feel?','Discuss: what happens if no one takes turns?'],simId:'turn-taking',buddy:'Even animals take turns! Wolves in a pack respect order. Cooperation evolved because groups that cooperated survived better.'},
{id:'c2-l2',title:'Listening Actively',subject:'Life Skills',classes:['2'],icon:'👂',bgGrad:'rgba(77,150,255,.18)',desc:'Practise listening without interrupting. Can you repeat what you heard?',ncert:'Life Skills – CBSE: Communication',why:'Active listening means focusing completely on the speaker, not planning your reply. We only remember 25–50% of what we hear — practising helps you retain more.',materials:['A partner','A short story to read aloud'],steps:['One person reads a 5-sentence story.','Listener: no interrupting! Make eye contact.','Listener repeats the story in their own words.','How much was remembered correctly?','Swap roles. Compare results.'],simId:'active-listen',buddy:'Good listeners make the best friends — and the best leaders. When you truly listen, people feel valued and trust you more.'},
{id:'c2-l3',title:'Problem Solving Steps',subject:'Life Skills',classes:['2'],icon:'🧩',bgGrad:'rgba(77,150,255,.18)',desc:'Learn a 4-step method to solve everyday problems calmly.',ncert:'Life Skills – CBSE: Critical Thinking',why:'The 4 steps: (1) Name the problem, (2) Think of solutions, (3) Pick the best one, (4) Try it and check.',materials:['Pencil and paper'],steps:['Think of a real problem you had recently.','Write step 1: What exactly is the problem?','Step 2: List 3 possible solutions.','Step 3: Pick the one with fewest bad effects.','Step 4: Try it. Did it work?'],simId:'problem-steps',buddy:'Scientists use the same process! It\'s called the scientific method. Every great invention started with someone identifying a problem and systematically solving it.'},
{id:'c2-l4',title:'Yes and No — Boundaries',subject:'Life Skills',classes:['2'],icon:'🛑',bgGrad:'rgba(77,150,255,.18)',desc:'Understand when to say yes and no. Practise using a firm, kind voice.',ncert:'Life Skills – CBSE: Personal Safety',why:'Knowing how to say "no" assertively (not aggressively or apologetically) is a fundamental life skill.',materials:['Role-play scenarios written on slips of paper'],steps:['Write 5 scenarios: friend asks to copy homework, stranger asks to come, etc.','For each: should you say yes or no?','Practise saying "No, I don\'t want to" in a firm, calm voice.','No need to give a reason for "no" — that\'s okay!','Discuss: is it rude to say no?'],simId:'boundaries-sim',buddy:'"No" is a complete sentence. You don\'t owe anyone an explanation for protecting yourself. Saying no clearly and kindly is a sign of self-respect.'},
{id:'c2-l5',title:'Helping at Home',subject:'Life Skills',classes:['2'],icon:'🏠',bgGrad:'rgba(77,150,255,.18)',desc:'List and take on age-appropriate chores. Understand why contributing matters.',ncert:'Life Skills – CBSE: Responsibility',why:'Children who do chores develop responsibility, time management, and a sense of contribution.',materials:['Paper','Pencil'],steps:['List 10 things that happen in your home every day.','Circle 3 things YOU could help with.','Plan: when will you do each?','Try for one week.','Ask a family member: did it help?'],simId:'chores-sim',buddy:'NASA astronauts on the space station each have assigned chores — cleaning, cooking, maintenance! Even in space, everyone contributes.'},

/* ══════════════ CLASS 3 ══════════════ */
{id:'c3-s1',title:'Simple Machines at Home',subject:'Science',classes:['5'],icon:'⚙️',bgGrad:'rgba(255,107,107,.18)',desc:'Find levers, wheels, and inclined planes hiding in everyday objects.',ncert:'NCERT Science Class 3 – Simple Machines',why:'The 6 simple machines reduce effort needed to do work. They don\'t save energy — they redirect or distribute it.',materials:['Look around your home'],steps:['Find a lever: scissors, see-saw, bottle opener, nutcracker.','Find a wheel and axle: doorknob, bicycle, fans.','Find an inclined plane: ramp, wedge, stairs.','Find a pulley: flag pole, window blinds.','For each: where is the effort, load and fulcrum?'],simId:'simple-machines',buddy:'Your forearm is a lever! The elbow is the fulcrum, muscles provide effort, and the hand holds the load. Your body is full of simple machines.'},
{id:'c3-s2',title:'Food Web Builder',subject:'Science',classes:['5'],icon:'🦅',bgGrad:'rgba(255,107,107,.18)',desc:'Build a food web for a forest ecosystem. Who eats whom?',ncert:'NCERT EVS Class 5 – Ch 1: Super Senses / Food Chains (concept explored one year early)',why:'A food web shows how energy flows through an ecosystem. Remove one species and the whole web can collapse — this is why biodiversity is so important.',materials:['Cards or paper strips','String or arrows'],steps:['Write on separate cards: grass, grasshopper, frog, snake, eagle, decomposers.','Draw arrows from eaten → eater.','Connect into a web (not just a chain).','Remove the frog card — what happens to the others?','Add a card for humans — where do we fit?'],simId:'food-web',buddy:'There are no waste products in a food web! Decomposers break down dead matter into nutrients that plants use. Nothing is truly wasted in nature.'},
{id:'c3-s4',title:'Erosion Experiment',subject:'Science',classes:['3'],icon:'🏔️',bgGrad:'rgba(255,107,107,.18)',desc:'Simulate how water causes soil erosion. Learn why roots are important.',ncert:'NCERT Science Class 3 – Land and Soil',why:'Erosion is the wearing away of topsoil by wind, water, or ice. Plant roots hold soil together. Deforestation removes this protection, causing landslides.',materials:['Two trays with soil','Grass/plant in one tray','Watering can'],steps:['Set up two trays: one bare soil, one with grass.','Tilt both at 30 degrees.','Pour the same amount of water on each.','Observe where more soil washes away.','Which tray stays intact? Why?'],simId:'erosion-sim',buddy:'The 2018 Kerala floods and landslides were worsened by deforestation in the Western Ghats. Roots literally hold mountains together!'},

{id:'c3-m1',title:'Fraction Folding',subject:'Maths',classes:['3'],icon:'🍕',bgGrad:'rgba(255,217,61,.18)',desc:'Fold paper into equal parts. See halves, thirds, quarters physically.',ncert:'NCERT Maths Class 3 – Fractions',why:'Fractions represent equal parts of a whole. Folding paper makes this concrete — you can\'t fold into "unequal thirds" and call them thirds!',materials:['3 squares of paper (same size)'],steps:['Fold square 1 in half — unfold and shade 1 part. That\'s 1/2.','Fold square 2 in half twice — 4 equal parts. Shade 1: that\'s 1/4.','Fold square 3 in thirds — shade 2 parts: 2/3.','Compare 1/2 and 1/4 — which is bigger?','Can you show 3/4 of a square?'],simId:'fraction-fold',buddy:'Fractions are everywhere! A recipe says ½ cup. A sale says ¼ off. A pizza is cut into 8 slices. Understanding fractions unlocks the real world.'},
{id:'c3-m2',title:'Perimeter Walk',subject:'Maths',classes:['3'],icon:'📐',bgGrad:'rgba(255,217,61,.18)',desc:'Measure the perimeter of rooms and objects using a tape measure.',ncert:'NCERT Maths Class 3 – Perimeter',why:'Perimeter is the total distance around a shape. It\'s found by adding all side lengths. Used in fencing land, framing pictures, fitting skirting boards.',materials:['Tape measure or string','Pencil and paper'],steps:['Measure the perimeter of your notebook (add all 4 sides).','Measure a room in your house.','Measure a non-rectangular shape (e.g. a table top).','If you walk around your school building, estimate the perimeter.','Find the perimeter of a triangle you draw.'],simId:'perimeter-sim',buddy:'Farmers measure land perimeter to decide how much fencing to buy. Road builders calculate perimeter to plan routes. Maths runs through every profession!'},
{id:'c3-m3',title:'Bar Graph Survey',subject:'Maths',classes:['3'],icon:'📊',bgGrad:'rgba(255,217,61,.18)',desc:'Survey your family on favourite foods or colours. Plot a bar graph.',ncert:'NCERT Maths Class 3 – Data Handling',why:'A bar graph represents data visually. The length of each bar shows the quantity, making it easy to compare. Data handling is key in science, business, and everyday decisions.',materials:['Paper with grid','Pencil and colours','5–10 people to survey'],steps:['Choose a question: "What\'s your favourite fruit?"','Survey 8–10 people. Tally results.','Draw a bar graph: x-axis = fruits, y-axis = number of people.','Draw and colour each bar.','What does your graph tell you?'],simId:'bar-graph',buddy:'Companies pay billions for data like this! Market research surveys tell businesses what products to make. You just did what a data scientist does!'},
{id:'c3-m4',title:'Division as Fair Sharing',subject:'Maths',classes:['3'],icon:'🍫',bgGrad:'rgba(255,217,61,.18)',desc:'Share objects equally into groups. Feel what division actually means.',ncert:'NCERT Maths Class 3 – Division',why:'Division is splitting into equal groups. 12 ÷ 4 = 3 means "share 12 equally among 4 people, each gets 3." It\'s the inverse of multiplication.',materials:['24 small objects (coins, seeds)'],steps:['Place 12 objects. Share equally among 3 friends.','How many did each get? 12 ÷ 3 = ?','Try 20 objects shared among 4.','What about 15 shared among 4? What\'s the remainder?','Write a real-life story for 18 ÷ 6 = 3.'],simId:'division-sharing',buddy:'Remainder is not a mistake! If 17 people need transport in 5-seater cars, you need 4 cars (with one person in the last car). Remainders matter!'},
{id:'c3-m5',title:'Area with Squares',subject:'Maths',classes:['3'],icon:'🔲',bgGrad:'rgba(255,217,61,.18)',desc:'Cover surfaces with square tiles. Count to find area.',ncert:'NCERT Maths Class 3 – Area',why:'Area is the amount of flat space a shape covers. We measure it in square units. Covering with tiles is the most intuitive way to build the concept.',materials:['1cm grid paper','Pencil','Ruler'],steps:['Draw different shapes on grid paper.','Count the complete squares inside each shape.','That\'s the area in square centimetres.','Draw a 4×5 rectangle — count squares — or just multiply!','Find the area of your notebook cover using L×W.'],simId:'area-squares',buddy:'Interior designers calculate area to know how much flooring, paint, or carpet to buy. Knowing area saves money and prevents waste!'},

{id:'c3-e1',title:'Composting Kitchen Waste',subject:'EVS',classes:['3'],icon:'♻️',bgGrad:'rgba(107,203,119,.18)',desc:'Start a mini compost bin. Turn kitchen waste into garden gold.',ncert:'NCERT EVS Class 3 – Waste and its Management',why:'Composting is natural recycling. Microorganisms break down organic waste into nutrient-rich humus, reducing landfill waste and returning nutrients to the soil.',materials:['A pot or bucket with holes','Kitchen scraps (vegetable peels, eggshells)','Dry leaves or newspaper','Soil'],steps:['Layer: dry material first, then kitchen scraps, then soil.','Keep moist but not wet.','Turn with a stick every 3 days.','After 3–4 weeks, observe: does it look like soil?','Use it on a plant — see if it grows faster!'],simId:'compost-sim',buddy:'One kilogram of kitchen waste becomes about 300g of rich compost. Composting at home can divert 30% of your household waste from landfill!'},
{id:'c3-e2',title:'Local Maps',subject:'EVS',classes:['3'],icon:'🗺️',bgGrad:'rgba(107,203,119,.18)',desc:'Draw a map of your neighbourhood. Learn map symbols and scale.',ncert:'NCERT EVS Class 3 – Our Neighbourhood',why:'Maps use symbols, scale, and direction (compass) to represent a real place. Drawing a map requires observation, spatial thinking, and precision.',materials:['Large paper','Pencil, ruler, colours'],steps:['Walk around your street/area. Note landmarks.','Draw a bird\'s eye (top-down) view.','Use symbols: square = house, blue = water, green = park.','Add a compass showing North.','Create a legend/key for your symbols.'],simId:'local-map',buddy:'Google Maps started as people drawing maps! Early cartographers were some of the most valued experts of their time — maps = power.'},
{id:'c3-e3',title:'Rock Cycle in a Bag',subject:'EVS',classes:['3'],icon:'🪨',bgGrad:'rgba(107,203,119,.18)',desc:'Use crayon shavings to simulate how rocks form, melt, and transform.',ncert:'NCERT EVS Class 3 – Rocks and Minerals',why:'The rock cycle shows how rocks transform: sedimentary (layers pressed), metamorphic (heat + pressure), igneous (melted and cooled). All rock types can transform over millions of years.',materials:['3 colours of crayons (peeled, shaved)','Zip-lock bag','Hot water basin (with adult)','Heavy book'],steps:['Shave crayons into 3 colour piles — like different rock types.','Layer them in the bag (sedimentary rock).','Press hard with a heavy book for 2 minutes (metamorphic).','Seal the bag, put in hot water 1 minute (igneous — melting).','Remove and observe. How did the layers change?'],simId:'rock-cycle',buddy:'Diamonds are just carbon atoms squeezed under enormous pressure for millions of years. The same element as graphite in your pencil — just rearranged!'},
{id:'c3-e4',title:'Adaptation Fashion Show',subject:'EVS',classes:['3'],icon:'🐘',bgGrad:'rgba(107,203,119,.18)',desc:'Present an animal and explain how its body is adapted to its habitat.',ncert:'NCERT EVS Class 3 – Animals and Adaptation',why:'Adaptations are physical or behavioural traits that help a species survive. They develop over millions of years through natural selection.',materials:['Paper for research','Drawing materials'],steps:['Choose an animal: camel, polar bear, dolphin, chameleon, etc.','Research: where does it live? What does it eat?','List 3 body adaptations that help it survive.','Draw the animal and label its adaptations.','Present to your family as a "fashion show" — explain each feature!'],simId:'adaptation-show',buddy:'The giraffe\'s long neck evolved over millions of years — ancestors who could reach higher leaves survived better and had more offspring. Survival of the fittest in action!'},
{id:'c3-e5',title:'Rainwater Harvesting Model',subject:'EVS',classes:['3'],icon:'🌧️',bgGrad:'rgba(107,203,119,.18)',desc:'Build a simple model showing how rooftop water is collected and stored.',ncert:'NCERT EVS Class 3 – Water Conservation',why:'Rainwater harvesting collects rain before it runs off, recharging groundwater. India receives 4000 billion cubic meters of rain annually — but captures only 6% of it.',materials:['Plastic bottle (cut as a roof)','Tube/straw','Container (as tank)','Sand as filter'],steps:['Cut a bottle diagonally to act as a sloped roof.','Attach a straw as a drainpipe.','Direct the straw into a container.','Add a layer of sand at the top as a filter.','Pour water on the "roof" — watch it collect!'],simId:'rain-harvest',buddy:'Traditional Kerala homes often had rain-fed wells. Your grandparents\' home might have used rainwater naturally!'},

{id:'c3-l1',title:'Goal Setting',subject:'Life Skills',classes:['3'],icon:'🎯',bgGrad:'rgba(77,150,255,.18)',desc:'Set a SMART goal for this week and track your progress daily.',ncert:'Life Skills – CBSE: Self-Management',why:'SMART goals are Specific, Measurable, Achievable, Relevant, and Time-bound. Vague goals are hard to act on. Specific goals work.',materials:['Paper','Pencil'],steps:['Write a vague goal: "get better at maths."','Convert it: "Solve 5 maths problems every day for 7 days."','Check: is it SMART? Tick each letter.','Put the paper somewhere visible.','At the end of the week: did you achieve it?'],simId:'goal-setting',buddy:'Olympic athletes don\'t just aim to "win." They set goals like "improve my 100m time by 0.3 seconds by March." Specificity is the engine of achievement.'},
{id:'c3-l2',title:'Growth vs Fixed Mindset',subject:'Life Skills',classes:['3'],icon:'🧠',bgGrad:'rgba(77,150,255,.18)',desc:"Learn the difference between \"I can't\" and \"I can't yet.\" Change your self-talk.",ncert:'Life Skills – CBSE: Emotional Intelligence',why:'Dr Carol Dweck\'s research shows students with a growth mindset — who believe ability can be developed — achieve significantly more.',materials:['Paper divided in two columns'],steps:['Column 1: Fixed thoughts ("I\'m bad at drawing").','Column 2: Rewrite each as growth ("I\'m practising, I\'ll improve").','Think of something you gave up on.','Rewrite what you\'d say with a growth mindset.','Try the thing again — just for 10 minutes.'],simId:'mindset-flip',buddy:'Your brain actually forms new connections when you struggle and persist. That temporary feeling of confusion? That\'s growth happening. Embrace the struggle!'},
{id:'c3-l3',title:'Teamwork Tower',subject:'Life Skills',classes:['3'],icon:'🏗️',bgGrad:'rgba(77,150,255,.18)',desc:'Build the tallest tower you can using newspaper. Only works with teamwork!',ncert:'Life Skills – CBSE: Teamwork',why:'Effective teamwork requires communication, role clarity, listening, and shared goals. Groups that discuss a plan before starting consistently outperform those who jump in.',materials:['20 sheets of newspaper','Tape','10-minute timer'],steps:['Form a team of 2–4 people.','Goal: build tallest freestanding tower using only newspaper and tape.','First 3 minutes: plan and discuss before touching materials.','Next 7 minutes: build.','Measure height. Reflect: what worked? What would you do differently?'],simId:'teamwork-tower',buddy:'NASA engineers who built the Apollo rocket were 400,000 people working together. No single person could have done it alone. Teamwork literally put humans on the moon!'},
{id:'c3-l4',title:'Conflict Resolution',subject:'Life Skills',classes:['3'],icon:'☮️',bgGrad:'rgba(77,150,255,.18)',desc:'Learn a 3-step method to resolve disagreements without fights.',ncert:'Life Skills – CBSE: Communication',why:'The 3-step method: (1) Each person states their view without interruption, (2) Find common ground, (3) Agree on a solution together.',materials:['Role-play scenario cards'],steps:['Write a conflict scenario: "Two friends both want the same book."','Person A states their view without interruption.','Person B listens, then states their view.','Together: find a solution that works for both.','Discuss: how does this feel different from arguing?'],simId:'conflict-resolve',buddy:'The United Nations was created to resolve conflicts between countries using words instead of war. The same skills you\'re learning now scale all the way up!'},
{id:'c3-l5',title:'Budget for a Party',subject:'Life Skills',classes:['3'],icon:'🎉',bgGrad:'rgba(77,150,255,.18)',desc:'Plan a birthday party with ₹500. Balance what you want with what you can afford.',ncert:'Life Skills – CBSE: Financial Literacy',why:'Budgeting means deciding how to use limited money before spending it. Every choice means giving up something else — this is called opportunity cost.',materials:['Paper and pencil'],steps:['Write: Party budget = ₹500.','List everything you\'d want: cake, snacks, decorations, games.','Estimate costs.','Add them up — over or under ₹500?','Cut or swap items to fit the budget.'],simId:'party-budget',buddy:'Planning before spending is the secret of every financially successful person. The poorest decisions happen when we buy on impulse without thinking ahead.'},

/* ══════════════ CLASS 4 ══════════════ */,
{id:'c4-s3',title:'Pulley and Effort',subject:'Science',classes:['5'],icon:'🏗️',bgGrad:'rgba(255,107,107,.18)',desc:'Use a pulley to lift a heavy load. Compare effort with and without it.',ncert:'NCERT EVS Class 5 – Ch 12: Simple Machines',why:'A single fixed pulley changes the direction of force (you pull down to lift up — much easier!). A moveable pulley halves the effort needed.',materials:['A cotton reel or smooth bottle cap as pulley','String','Small weight','Tape'],steps:['Attach the pulley to a high point.','Thread a string through it. Attach weight.','Pull the string — notice direction change.','Compare: lifting weight directly vs. using pulley.','Which felt easier?'],simId:'pulley-sim',buddy:'Tower cranes, flagpoles, window blinds, and elevators all use pulleys. Block-and-tackle pulley systems on old sailing ships could multiply force by 6×!'},

{id:'c4-m1',title:'Large Number Place Value',subject:'Maths',classes:['4'],icon:'🔢',bgGrad:'rgba(255,217,61,.18)',desc:'Build numbers up to 1 lakh using abacus or place value cards.',ncert:'NCERT Maths Class 4 – Large Numbers',why:'Our number system is positional — the value of a digit depends on its position. 5 in "500" is worth 100× more than 5 in "5."',materials:['Abacus or beads on sticks in sand','Place value chart'],steps:['Write the number 47,362.','Read it: "Forty-seven thousand, three hundred sixty two."','Find the value of each digit.','Add 1,000: what changes?','Round to nearest thousand.'],simId:'place-value',buddy:'The concept of zero was invented in India! Before zero, large calculations were incredibly difficult. Zero makes our whole place value system work.'},
{id:'c4-m2',title:'Fraction Equivalence',subject:'Maths',classes:['4'],icon:'🍰',bgGrad:'rgba(255,217,61,.18)',desc:'Discover that 1/2 = 2/4 = 4/8. See equivalent fractions visually.',ncert:'NCERT Maths Class 4 – Fractions',why:'Equivalent fractions represent the same amount. Multiply or divide numerator and denominator by the same number to find equivalents.',materials:['3 strips of equal-length paper'],steps:['Fold strip 1 in half. Shade one part = 1/2.','Fold strip 2 in quarters. Shade two parts = 2/4.','Fold strip 3 in eighths. Shade four parts = 4/8.','Hold all 3 side by side — shaded areas are equal!','Write: 1/2 = 2/4 = 4/8.'],simId:'fraction-equiv',buddy:'When you simplify a fraction, you\'re finding the simplest equivalent: 8/12 = 2/3. The value stays the same — like trading four ₹5 coins for a ₹20 note!'},
{id:'c4-m3',title:'Angles Around Us',subject:'Maths',classes:['4'],icon:'📐',bgGrad:'rgba(255,217,61,.18)',desc:'Measure angles in real objects using a protractor. Classify as acute, right, or obtuse.',ncert:'NCERT Maths Class 4 – Geometry – Angles',why:'An angle measures the turn between two lines. Right angles (90°) are everywhere in architecture. Acute (<90°) and obtuse (>90°) angles are in natural shapes.',materials:['Protractor','Pencil','Ruler'],steps:['Draw 5 different angles.','Measure each with a protractor.','Classify each: acute, right, obtuse.','Find a right angle in your room (wall meets floor).','What angle does a clock show at 3:00? At 6:00?'],simId:'angles-sim',buddy:'Builders and carpenters use angles constantly. A roof slope is measured in angles. Roads with too steep an angle (>15°) are dangerous for vehicles to climb!'},
{id:'c4-m4',title:'Decimal Introduction',subject:'Maths',classes:['4'],icon:'💱',bgGrad:'rgba(255,217,61,.18)',desc:'Use money to understand decimals. ₹12.50 makes decimals real!',ncert:'NCERT Maths Class 4 – Decimals',why:'A decimal point separates whole units from parts of a unit. ₹12.50 = 12 full rupees and 50 paise (half a rupee).',materials:['Coins (50 paise, ₹1, ₹5, ₹10)','Price list from home'],steps:['Count: 3 rupees and 50 paise = ₹3.50.','Write the decimal for 7 rupees 75 paise.','Add ₹4.25 + ₹3.50.','What\'s the change from ₹20 if you spend ₹13.75?','Write today\'s price of 1 litre milk as a decimal.'],simId:'decimal-intro',buddy:'Decimals were formally introduced to Europe in 1585 — but Indian mathematicians used decimal fractions centuries earlier! The metric system (mm, cm, m, km) is all decimals.'},
{id:'c4-m5',title:'Symmetry in Nature',subject:'Maths',classes:['4'],icon:'🦋',bgGrad:'rgba(255,217,61,.18)',desc:'Find lines of symmetry in leaves, butterflies, and shapes.',ncert:'NCERT Maths Class 4 – Symmetry',why:'A shape has symmetry if a mirror line divides it into two identical halves. Bilateral symmetry (one line) is common in animals. Radial symmetry appears in flowers.',materials:['Leaves, butterfly pictures','Mirror or fold test','Paper and pencil'],steps:['Fold a leaf in half — does it match? That\'s bilateral symmetry.','Draw a butterfly and fold — both wings identical?','Try a square — how many lines of symmetry? (4!)','Try a circle — infinite lines!','Draw letters of the alphabet — which have symmetry?'],simId:'symmetry-nature',buddy:'Human faces are approximately symmetrical — and studies show that more symmetrical faces are rated as more attractive. Symmetry signals healthy development to our brains!'},

{id:'c4-e1',title:'Crop Seasons',subject:'EVS',classes:['4'],icon:'🌾',bgGrad:'rgba(107,203,119,.18)',desc:'Match crops to their growing seasons. Understand Kharif, Rabi, and Zaid.',ncert:'NCERT EVS Class 4 – Agriculture',why:'Kharif crops (rice, maize, cotton) grow in monsoon (June–Nov). Rabi crops (wheat, mustard, peas) grow in winter (Nov–April). Zaid crops (watermelon) grow in summer.',materials:['Cards with crop names','Calendar'],steps:['Write 10 crops on cards.','Sort them into Kharif or Rabi based on when they\'re planted.','Research which crops are grown in your state.','Find 3 Kharif crops and 3 Rabi crops grown in India.','Which monsoon months are most critical for rice farmers in West Bengal?'],simId:'crop-seasons',buddy:'India grows over 200 types of crops across three seasons. The monsoon makes Kharif possible — if the rain is late by even 2 weeks, millions of farmers delay sowing and the whole country\'s food calendar shifts.'},
{id:'c4-e2',title:'States and Capitals Map',subject:'EVS',classes:['4'],icon:'🗺️',bgGrad:'rgba(107,203,119,.18)',desc:'Place all 28 Indian states on a blank map and add their capitals.',ncert:'NCERT EVS Class 4 – Our Country India',why:'India has 28 states and 8 union territories, each with a unique culture, language, and geography. Understanding India\'s geography builds civic pride.',materials:['Printed blank India map','Pencil and colours','Atlas or reference'],steps:['Label your home state first (Kerala).','Find and mark the 4 neighbouring states.','Add the 5 largest states by area.','Mark state capitals with a star.','Colour by region: South, North, East, West, Northeast.'],simId:'india-map',buddy:'India is so diverse that within 100km you can find different languages, foods, and landscapes. Kerala alone has beaches, mountains, forests, and backwaters all within 3 hours drive!'},
{id:'c4-e3',title:'Air Pollution Monitor',subject:'EVS',classes:['4'],icon:'🏭',bgGrad:'rgba(107,203,119,.18)',desc:'Make a simple air quality test using vaseline-coated cards. Count particles!',ncert:'NCERT EVS Class 4 – Air Pollution',why:'Particulate matter (PM2.5 and PM10) are tiny particles in polluted air. This experiment makes invisible air pollution visible!',materials:['White index cards','Vaseline','Magnifying glass','String to hang cards'],steps:['Coat 3 cards with vaseline.','Hang them in different spots: inside, roadside, garden.','After 24 hours, collect them.','Examine with magnifying glass — count dark specks.','Which location had most particles?'],simId:'air-monitor',buddy:'Delhi\'s AQI sometimes exceeds 500 — 10× the WHO safe limit! But Kerala generally has some of India\'s cleanest air due to forest cover and rainfall. Protect those forests!'},
{id:'c4-e4',title:'Water Cycle Terrarium',subject:'EVS',classes:['4'],icon:'🌊',bgGrad:'rgba(107,203,119,.18)',desc:'Model the full water cycle in a glass terrarium.',ncert:'NCERT EVS Class 4 – Water Cycle',why:'The water cycle continuously moves water between oceans, atmosphere, and land. Solar energy drives evaporation; gravity drives precipitation and river flow.',materials:['Large clear container with lid','Small amount of soil and pebbles','Water','Plastic wrap or lid'],steps:['Layer pebbles, then soil in one corner.','Pour a little water at the opposite side (ocean).','Seal the container with plastic wrap.','Place in sunlight.','After a few hours: see condensation on the lid and droplets falling!'],simId:'terrarium-cycle',buddy:'The water you\'re drinking today is the same water that has been cycling for 4 billion years. There is no new water being created on Earth. Every drop is ancient!'},
{id:'c4-e5',title:'Landforms 3D Model',subject:'EVS',classes:['4'],icon:'⛰️',bgGrad:'rgba(107,203,119,.18)',desc:'Build mountains, valleys, plateaus and plains using clay or salt dough.',ncert:'NCERT EVS Class 4 – Landforms',why:'Landforms are shaped by tectonic forces, erosion, and volcanic activity. Understanding landforms helps us understand why settlements develop where they do.',materials:['Salt dough (flour+salt+water) or clay','A large flat board','Paint (optional)'],steps:['Make a flat base — this is a plain.','Build up a mountain range on one side.','Carve a valley between mountains with a spoon.','Create a plateau (flat top, steep sides).','Add a river flowing from mountain to sea.'],simId:'landforms-model',buddy:'The Western Ghats (where Idukki is!) were formed when India broke off from Africa 130 million years ago. The mountains are older than the Himalayas!'},

{id:'c4-l1',title:'Time Management Grid',subject:'Life Skills',classes:['4'],icon:'⏳',bgGrad:'rgba(77,150,255,.18)',desc:'Use the Eisenhower Matrix to sort tasks by urgent vs. important.',ncert:'Life Skills – CBSE Class 4',why:'The Eisenhower Matrix sorts tasks into 4 boxes: Urgent+Important=Do now; Important+Not urgent=Schedule; Urgent+Not important=Delegate; Neither=Drop.',materials:['Paper divided into 4 quadrants'],steps:['Label: Q1 Urgent+Important, Q2 Important+Not urgent, Q3 Urgent+Not important, Q4 Neither.','List 8 activities from your day.','Sort each into a quadrant.','Which quadrant has most items? (Q1 means always in crisis mode!)','Plan to spend more time in Q2.'],simId:'time-matrix',buddy:'President Eisenhower said: "What is important is seldom urgent, and what is urgent is seldom important." Spending time on Q2 prevents things from becoming Q1 crises.'},
{id:'c4-l2',title:'Responsibility Chart',subject:'Life Skills',classes:['4'],icon:'✅',bgGrad:'rgba(77,150,255,.18)',desc:'Identify your responsibilities at home and school. Commit to them for a week.',ncert:'Life Skills – CBSE: Responsibility',why:'Responsibility means ownership — not just completing tasks but caring about quality and impact. Taking responsibility builds trust, which is the foundation of all relationships.',materials:['Paper with a weekly chart grid'],steps:['List your responsibilities: homework, room tidiness, a chore.','Rate current completion: 0–5.','Set a target for each.','Track daily for one week.','At week end: which improved? What helped?'],simId:'responsibility-chart',buddy:'Studies show that kids given genuine responsibilities develop stronger leadership abilities and self-esteem. Responsibility is a gift, not a burden.'},
{id:'c4-l3',title:'Digital Safety Basics',subject:'Life Skills',classes:['4'],icon:'🔒',bgGrad:'rgba(77,150,255,.18)',desc:'Learn what personal information to never share online. Create strong passwords.',ncert:'Life Skills – CBSE: Digital Safety',why:'Online predators and scammers target children who share personal info. A strong password uses uppercase, lowercase, numbers, and symbols.',materials:['Paper and pencil'],steps:['List: name, address, school, phone, password. Mark each Safe/Unsafe to share online.','Create a strong password: 3 random words + number + symbol (e.g. Mango7Cloud!).','Check: is it easy to remember but hard to guess?','Discuss: what happens if someone else knows your password?','Rule: only share passwords with parents.'],simId:'digital-safety',buddy:'The most common passwords are "123456" and "password." Hackers try these first. A random 12-character password would take a computer 34,000 years to crack!'},
{id:'c4-l4',title:'Leadership in a Group',subject:'Life Skills',classes:['4'],icon:'👑',bgGrad:'rgba(77,150,255,.18)',desc:'Experience leading and following. Discover what makes a good leader.',ncert:'Life Skills – CBSE: Leadership',why:'Good leaders listen more than they speak, give credit to others, admit mistakes, and serve the group\'s goal rather than their own ego.',materials:['A group of 3–5 friends or family','A simple task: build something, plan something'],steps:['One person leads the group in a 10-minute task.','Rotate: each person leads a different task.','After each, rate the leader: Did they listen? Were they clear?','Discuss: which style worked best?','What kind of leader do you want to be?'],simId:'leadership-sim',buddy:'The best leaders say "we" not "I." Nelson Mandela, APJ Abdul Kalam, and Malala Yousafzai all led by serving others first.'},
{id:'c4-l5',title:'Healthy vs Junk Food Audit',subject:'Life Skills',classes:['4'],icon:'🥗',bgGrad:'rgba(77,150,255,.18)',desc:'Audit what you eat in a day. Calculate how much is healthy vs. junk.',ncert:'Life Skills – CBSE: Health',why:'Ultra-processed foods high in sugar, salt, and artificial additives are designed to be addictive. Understanding food labels helps you make informed choices.',materials:['A day\'s worth of food wrappers/labels','Paper','Pencil'],steps:['List everything you ate today.','Mark each: Whole food (fruits, veg, grains, pulses) or Processed (packets, fried, sugary).','Count each category. What percentage is whole food?','Read the ingredient list of one packet food — how many ingredients?','Set a goal for tomorrow.'],simId:'food-audit',buddy:'A study found that children who learn to cook whole foods eat 24% more vegetables as adults. Cooking is a life skill that literally saves your life — and money!'},

/* ══════════════ CLASS 5 ══════════════ */,

{id:'c5-m1',title:'Prime and Composite Numbers',subject:'Maths',classes:['5'],icon:'🔢',bgGrad:'rgba(255,217,61,.18)',desc:'Sieve of Eratosthenes: find all primes up to 100.',ncert:'NCERT Maths Class 5 – Numbers',why:'A prime number has exactly 2 factors: 1 and itself. The Sieve of Eratosthenes (250 BC) is an ancient algorithm to find all primes.',materials:['A 10×10 grid numbered 1–100'],steps:['Cross out 1 (not prime).','Circle 2. Cross out all multiples of 2.','Circle 3. Cross out all multiples of 3.','Continue with 5, 7 (next uncrossed).','All remaining circled numbers are prime!'],simId:'prime-sieve',buddy:'The largest known prime number (as of 2024) has 41 million digits! Primes are used to encrypt your bank transactions — they\'re the foundation of internet security.'},
{id:'c5-m2',title:'Volume of Cuboids',subject:'Maths',classes:['5'],icon:'📦',bgGrad:'rgba(255,217,61,.18)',desc:'Fill boxes with unit cubes. Discover V = L × W × H.',ncert:'NCERT Maths Class 5 – Volume',why:'Volume measures 3D space. Filling with unit cubes makes the formula L×W×H intuitive: counting cubes in one layer (L×W) multiplied by the number of layers (H).',materials:['Centimetre cubes or sugar cubes','Small boxes (matchbox, shoe box)'],steps:['Fill one layer of a matchbox with cubes. Count.','Stack another layer. Count total.','Add layers until box is full.','Does L×W×H give the same number?','Measure your pencil box — calculate volume without filling!'],simId:'volume-sim',buddy:'Ships are designed so their volume below the waterline displaces enough water to support the ship\'s weight. Archimedes figured this out in a bathtub!'},
{id:'c5-m4',title:'Tessellations',subject:'Maths',classes:['5'],icon:'🔷',bgGrad:'rgba(255,217,61,.18)',desc:'Tile a surface with shapes so there are no gaps. Create beautiful patterns!',ncert:'NCERT Maths Class 5 – Geometry',why:'A tessellation tiles a plane without gaps or overlaps. Only certain shapes tessellate: triangles, squares, hexagons. Honeybees use hexagonal tessellation — it uses the least wax!',materials:['Cardboard cut into triangles and hexagons','Paper','Pencil'],steps:['Trace a triangle repeatedly, fitting edges together.','Does it tile without gaps? (Yes!)','Try with pentagons — any gaps?','Try hexagons — they tile perfectly!','Create an artistic tessellation pattern and colour it.'],simId:'tessellation-sim',buddy:'The Islamic art in the Alhambra palace in Spain has 17 different types of geometric tessellations. MC Escher famously used tessellations to create mind-bending art with birds and fish.'},

{id:'c5-e1',title:'Climate vs Weather',subject:'EVS',classes:['5'],icon:'🌍',bgGrad:'rgba(107,203,119,.18)',desc:'Compare weather (today) vs climate (30-year patterns). Analyse data!',ncert:'NCERT EVS Class 5 – Climate',why:'Weather is the current atmosphere state; climate is the 30-year average. "Climate change" means long-term shifts in those averages.',materials:['Internet or newspaper access','Graph paper'],steps:['Find monthly rainfall averages for your city.','Plot as a bar chart.','Mark which months are monsoon.','Compare to this year\'s actual rainfall.','Is this year drier or wetter than average?'],simId:'climate-weather',buddy:"Kerala's monsoon typically arrives June 1. But records show it's arriving later in recent years. That's climate change in action — you can measure it yourself!"},
{id:'c5-e2',title:'Renewable vs Non-Renewable',subject:'EVS',classes:['5'],icon:'🌞',bgGrad:'rgba(107,203,119,.18)',desc:'Classify energy sources. Calculate how long fossil fuels will last.',ncert:'NCERT EVS Class 5 – Energy Resources',why:'Renewable energy (solar, wind, hydro) replenishes naturally. Fossil fuels took millions of years to form and are depleting rapidly.',materials:['Cards with energy sources','Paper for sorting'],steps:['Sort 10 energy sources: solar, coal, wind, petrol, hydro, gas, biomass, tidal, nuclear.','Mark each as renewable or non-renewable.','For each non-renewable, write what could replace it.','Research: how much of Kerala\'s energy is from hydro?','What % could come from solar in your district?'],simId:'energy-types',buddy:"Kerala gets ~60% of its electricity from hydropower! But in drought years, this drops. That's why we need a mix of renewables — sun shines when rain doesn't come."},
{id:'c5-e3',title:'Biodiversity Survey',subject:'EVS',classes:['5'],icon:'🦎',bgGrad:'rgba(107,203,119,.18)',desc:'Survey all living species in a 1m² patch of ground. Calculate diversity.',ncert:'NCERT EVS Class 5 – Biodiversity',why:'Biodiversity is the variety of life in an area. High biodiversity = healthy ecosystem. Scientists measure biodiversity using species counts per area.',materials:['4 sticks','String to mark 1m²','Magnifying glass','Notebook'],steps:['Mark a 1m² square in your garden or school ground.','Count and list every living thing you can find.','Include: plants, insects, worms, birds overhead, etc.','How many different species?','Compare with a 1m² of concrete — how many there?'],simId:'biodiversity-survey',buddy:"The Western Ghats (Kerala's mountains) are one of the world's 36 biodiversity hotspots — areas with exceptional species richness found nowhere else on Earth."},
{id:'c5-e4',title:'Newspaper to History',subject:'EVS',classes:['5'],icon:'📰',bgGrad:'rgba(107,203,119,.18)',desc:'Read today\'s newspaper. Find stories that will be history in 50 years.',ncert:'NCERT EVS Class 5 – History Around Us',why:'History is just documented current events. The newspaper is tomorrow\'s history book. Developing the habit of reading news builds civic awareness.',materials:['Any daily newspaper (Malayalam or English)'],steps:['Read the front page completely.','Identify 3 stories: political, scientific, environmental.','For each: why will this matter in 50 years?','Find one good news story — there\'s always one!','Write a 3-sentence "future history" summary for the most important story.'],simId:'news-history',buddy:"Manorama News archives go back decades. Future historians will use today's papers to understand how we lived. You're reading primary sources!"},
{id:'c5-e5',title:'Trade Routes Then and Now',subject:'EVS',classes:['5'],icon:'🚢',bgGrad:'rgba(107,203,119,.18)',desc:'Trace ancient spice trade routes. Compare to modern shipping lanes.',ncert:'NCERT EVS Class 5 – History & Trade',why:'Kerala was at the centre of ancient spice trade — Arab, Chinese, Roman, and later Portuguese traders came for pepper, cardamom, and cinnamon. This shaped Kerala\'s culture, religion, and even DNA.',materials:['World map printout','Pencil','Colours'],steps:['Mark Kerala on the map.','Draw the ancient Arab spice route to the Middle East.','Draw the Portuguese route (around Africa).','Mark where these spices ended up (Europe, Middle East).','Draw modern shipping from Kochi port to major markets.'],simId:'trade-routes',buddy:"Your cardamom estate is part of a trade tradition thousands of years old! 'Black gold' — pepper from Kerala — was once worth more than gold by weight in Europe."},

{id:'c5-l1',title:'Financial Goal Tracker',subject:'Life Skills',classes:['5'],icon:'🐷',bgGrad:'rgba(77,150,255,.18)',desc:'Set a savings goal and track weekly progress. Discover compound patience.',ncert:'Life Skills – CBSE: Financial Literacy',why:'Saving requires delayed gratification — choosing future benefit over immediate pleasure.',materials:['A jar for savings','Paper for tracking'],steps:['Choose a goal: something costing ₹200–500.','Decide how to earn or save the money.','Set a weekly savings target.','Track each week in a chart.','Calculate: how many weeks to reach goal?'],simId:'savings-tracker',buddy:'If you save ₹100/month from age 15 in a mutual fund earning 12%/year, you\'ll have ₹1.9 crore by age 60. Starting early is the single biggest financial advantage.'},
{id:'c5-l2',title:'Debate: Two Sides',subject:'Life Skills',classes:['5'],icon:'🗣️',bgGrad:'rgba(77,150,255,.18)',desc:'Argue both sides of a topic. Learn that every issue has multiple perspectives.',ncert:'Life Skills – CBSE: Critical Thinking',why:'Arguing a position you disagree with is one of the most powerful ways to develop critical thinking. It forces you to understand the strongest version of the other side.',materials:['A topic card','2 minutes prep per side'],steps:['Choose: "Should there be homework?" or any relatable topic.','Prepare 3 arguments FOR homework.','Prepare 3 arguments AGAINST.','Argue one side for 2 minutes.','Swap and argue the other side.'],simId:'debate-sim',buddy:"The best debaters don't just know their own arguments — they know the opposition's better than the opposition does! That's how they win."},
{id:'c5-l3',title:'Media Literacy: Real or Fake?',subject:'Life Skills',classes:['5'],icon:'📱',bgGrad:'rgba(77,150,255,.18)',desc:'Fact-check 5 viral messages. Spot misinformation red flags.',ncert:'Life Skills – CBSE: Digital Literacy',why:'Misinformation spreads 6× faster than true information on social media. Key red flags: no source cited, sensational language, request to "share immediately."',materials:['5 example WhatsApp forwards (made up scenarios)','Access to Google'],steps:['Read a message: "Scientists confirm chocolate cures cancer!"','Red flags: Who said this? Which scientists? What publication?','Google: search the claim + "fact check."','Check fact-checking sites: Boom, Alt News, AFP Fact Check.','Classify: True, Misleading, or False.'],simId:'fact-check',buddy:'Before sharing anything, ask: WHO is saying this? WHY might they want me to believe/share it? WHAT evidence do they provide? Three questions can stop a lot of harm.'},
{id:'c5-l4',title:'Stress Busters Toolkit',subject:'Life Skills',classes:['5'],icon:'🧘',bgGrad:'rgba(77,150,255,.18)',desc:'Learn 5 evidence-based stress reduction techniques. Build your personal toolkit.',ncert:'Life Skills – CBSE: Mental Health',why:'Stress activates the "fight or flight" response. These techniques activate the "rest and digest" system instead.',materials:['Just yourself'],steps:['4-7-8 Breathing: inhale 4 counts, hold 7, exhale 8. Repeat 3×.','5-4-3-2-1: name 5 things you see, 4 hear, 3 touch, 2 smell, 1 taste.','Progressive muscle relaxation: tense each muscle group for 5 seconds, release.','Write down 3 good things that happened today.','Move your body for 5 minutes — any movement!'],simId:'stress-tools',buddy:'The 4-7-8 breath activates the parasympathetic nervous system in under a minute. It\'s used by surgeons before operations and athletes before big moments.'},
{id:'c5-l5',title:'Community Problem Solving',subject:'Life Skills',classes:['5'],icon:'🏘️',bgGrad:'rgba(77,150,255,.18)',desc:'Identify one problem in your community. Plan a small action to address it.',ncert:'Life Skills – CBSE: Civic Responsibility',why:'Young people who take civic action develop stronger sense of agency and purpose. Even small actions build the belief that you can make a difference.',materials:['Notebook','Pencil','Willingness to observe your community'],steps:['Walk around your neighbourhood.','List 5 problems you observe: litter, broken path, stray dogs, etc.','Pick one you could realistically address.','Plan 3 actions you could take.','Take action 1 this week!'],simId:'community-action',buddy:'Greta Thunberg started climate strikes at age 15. Age is not a barrier — conviction and action are what matter.'},

]; // end of Part 1 — classes 1–5
